import React from "react";
import { Dashboard, Login, PrivateRoute, AuthWrapper, Error } from "./pages";
import { BrowserRouter as Router, Switch, Route } from "react-router-dom";

function App() {
  return (
    <ThemeProvider theme={{ mode: "dark" }}>
      <>
        <GlobalStyle />
        <div>
          <Dashboard></Dashboard>
          <Login />
          <Error />
        </div>
      </>
    </ThemeProvider>
  );
}

export default App;
